import React from 'react';
import { useNavigate } from 'react-router-dom';

const CourseCard = ({ course }) => {
  const navigate = useNavigate();

  const handleClick = () => {
    navigate(`/course/${course.id}`);
  };

  // Course icon based on name
  const getCourseIcon = (name) => {
    const nameLower = name?.toLowerCase() || '';
    if (nameLower.includes('btech') || nameLower.includes('b.tech')) return '💻';
    if (nameLower.includes('bca')) return '📱';
    if (nameLower.includes('bba')) return '📊';
    if (nameLower.includes('mba')) return '🎓';
    if (nameLower.includes('mca')) return '💼';
    return '📚';
  };

  // Format course name
  const formatCourseName = (name) => {
    if (!name) return '';
    if (name.toLowerCase().includes('btech')) return 'B.Tech';
    if (name.toLowerCase().includes('bca')) return 'BCA';
    if (name.toLowerCase().includes('bba')) return 'BBA';
    if (name.toLowerCase().includes('mba')) return 'MBA';
    if (name.toLowerCase().includes('mca')) return 'MCA';
    return name;
  };

  const styles = {
    card: {
      background: 'white',
      borderRadius: '16px',
      padding: '2rem',
      boxShadow: '0 4px 6px rgba(0, 0, 0, 0.1)',
      textAlign: 'center',
      transition: 'all 0.3s ease',
      cursor: 'pointer',
      border: '1px solid #e5e7eb',
      height: '100%',
      display: 'flex',
      flexDirection: 'column',
      alignItems: 'center',
      justifyContent: 'center',
      minHeight: '200px'
    },
    icon: {
      fontSize: '3rem',
      marginBottom: '1rem',
      background: 'linear-gradient(135deg, #4f46e5, #7c3aed)',
      width: '80px',
      height: '80px',
      borderRadius: '50%',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      color: 'white',
      margin: '0 auto 1rem'
    },
    title: {
      fontSize: '1.5rem',
      fontWeight: '700',
      color: '#1f2937',
      marginBottom: '0.5rem'
    },
    clickHint: {
      fontSize: '0.85rem',
      color: '#9ca3af',
      display: 'flex',
      alignItems: 'center',
      gap: '0.3rem',
      marginTop: '0.5rem'
    }
  };

  return (
    <div 
      style={styles.card} 
      onClick={handleClick}
      onMouseEnter={(e) => {
        e.currentTarget.style.transform = 'translateY(-5px)';
        e.currentTarget.style.boxShadow = '0 20px 40px rgba(79, 70, 229, 0.2)';
        e.currentTarget.style.borderColor = '#4f46e5';
      }}
      onMouseLeave={(e) => {
        e.currentTarget.style.transform = 'translateY(0)';
        e.currentTarget.style.boxShadow = '0 4px 6px rgba(0, 0, 0, 0.1)';
        e.currentTarget.style.borderColor = '#e5e7eb';
      }}
    >
      {/* Icon */}
      <div style={styles.icon}>
        {getCourseIcon(course.name)}
      </div>

      {/* Course Name */}
      <h3 style={styles.title}>{formatCourseName(course.name)}</h3>

      {/* Click Hint */}
      <div style={styles.clickHint}>
        <span>👆</span> Click to view course
      </div>
    </div>
  );
};

export default CourseCard;
